<?php
 namespace WPAICG\Chat\Storage\LoggerMethods; if (!defined('ABSPATH')) { exit; } function insert_new_log_logic( \wpdb $wpdb, string $table_name, ?int $bot_id, ?int $user_id, ?string $session_id, string $conversation_uuid, string $module, int $is_guest, array $new_message, int $current_timestamp, ?string $ip_to_store, ?string $user_wp_role ): array|false { $parent_id = generate_parent_id_logic(); $messages_array = [$new_message]; $conversation_data = [ 'parent_id' => $parent_id, 'messages' => $messages_array, ]; $insert_data_fields = [ 'bot_id' => $bot_id, 'user_id' => $user_id, 'session_id' => $session_id, 'conversation_uuid' => $conversation_uuid, 'module' => $module, 'is_guest' => $is_guest, 'messages' => wp_json_encode($conversation_data, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), 'message_count' => 1, 'first_message_ts' => $current_timestamp, 'last_message_ts' => $current_timestamp, 'ip_address' => $ip_to_store, 'user_wp_role' => $user_wp_role ? sanitize_text_field($user_wp_role) : null, 'created_at' => current_time('mysql', 1), 'updated_at' => current_time('mysql', 1), ]; $formats_map = ['%d', '%d', '%s', '%s', '%s', '%d', '%s', '%d', '%d', '%d', '%s', '%s', '%s', '%s']; $data_to_insert = []; $formats_to_use = []; foreach ($insert_data_fields as $key => $value) { $data_to_insert[$key] = $value; $key_index = array_search($key, array_keys($insert_data_fields)); if ($key_index !== false) { $formats_to_use[] = $formats_map[$key_index]; } } $inserted = $wpdb->insert($table_name, $data_to_insert, $formats_to_use); if ($inserted === false) { return false; } $new_log_id = $wpdb->insert_id; return ['log_id' => $new_log_id, 'message_id' => $new_message['message_id'], 'is_new_session' => true]; }